/* Kraken UI Kit — theme mapping (portable).
   Re-points shadcn's semantic CSS vars (--primary, --background, …) at the
   Kraken 3-layer design tokens (--ds-*). Because the Figma semantic layer
   already uses shadcn names verbatim, this is a 1:1 alias map.

   Pair this with tokens.css (the --ds-* values). Brand switching happens one
   layer down in tokens.css via [data-theme="<brand>"] on <html>, so the vars
   below need no per-brand overrides — each var() re-resolves when the brand
   flips. Imported by globals.css; also shipped by the shadcn registry `theme`
   item so consumers get identical theming. Keep in sync with tokens.css. */

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --font-sans: var(--font-sans);
  --font-mono: var(--font-geist-mono);
  --font-heading: var(--font-sans);
  --color-sidebar-ring: var(--sidebar-ring);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar: var(--sidebar);
  --color-chart-5: var(--chart-5);
  --color-chart-4: var(--chart-4);
  --color-chart-3: var(--chart-3);
  --color-chart-2: var(--chart-2);
  --color-chart-1: var(--chart-1);
  --color-ring: var(--ring);
  --color-input: var(--input);
  --color-border: var(--border);
  --color-destructive: var(--destructive);
  --color-accent-foreground: var(--accent-foreground);
  --color-accent: var(--accent);
  --color-muted-foreground: var(--muted-foreground);
  --color-muted: var(--muted);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-secondary: var(--secondary);
  --color-primary-foreground: var(--primary-foreground);
  --color-primary: var(--primary);
  --color-popover-foreground: var(--popover-foreground);
  --color-popover: var(--popover);
  --color-card-foreground: var(--card-foreground);
  --color-card: var(--card);
  --radius-sm: calc(var(--radius) * 0.6);
  --radius-md: calc(var(--radius) * 0.8);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) * 1.4);
  --radius-2xl: calc(var(--radius) * 1.8);
  --radius-3xl: calc(var(--radius) * 2.2);
  --radius-4xl: calc(var(--radius) * 2.6);
}

:root {
  /* App font follows the active brand: jit → "Moderat JIT", brand → "Noto Sans". */
  --font-sans: var(--ds-typography-bodymd-fontfamily), ui-sans-serif, system-ui, -apple-system, sans-serif;
  --background: var(--ds-color-background);
  --foreground: var(--ds-color-foreground);
  --card: var(--ds-color-card);
  --card-foreground: var(--ds-color-card-foreground);
  --popover: var(--ds-color-popover);
  --popover-foreground: var(--ds-color-popover-foreground);
  --primary: var(--ds-color-primary);
  --primary-foreground: var(--ds-color-primary-foreground);
  --secondary: var(--ds-color-secondary);
  --secondary-foreground: var(--ds-color-secondary-foreground);
  --muted: var(--ds-color-muted);
  --muted-foreground: var(--ds-color-muted-foreground);
  --accent: var(--ds-color-accent);
  --accent-foreground: var(--ds-color-accent-foreground);
  --destructive: var(--ds-color-destructive);
  --border: var(--ds-color-border);
  --input: var(--ds-color-input);
  --ring: var(--ds-color-ring);
  --chart-1: var(--ds-chart-color-1);
  --chart-2: var(--ds-chart-color-2);
  --chart-3: var(--ds-chart-color-3);
  --chart-4: var(--ds-chart-color-4);
  --chart-5: var(--ds-chart-color-5);
  --radius: var(--ds-radius-md);
  --sidebar: var(--ds-color-sidebar);
  --sidebar-foreground: var(--ds-color-sidebar-foreground);
  --sidebar-primary: var(--ds-color-sidebar-primary);
  --sidebar-primary-foreground: var(--ds-color-sidebar-primary-foreground);
  --sidebar-accent: var(--ds-color-sidebar-accent);
  --sidebar-accent-foreground: var(--ds-color-sidebar-accent-foreground);
  --sidebar-border: var(--ds-color-sidebar-border);
  --sidebar-ring: var(--ds-color-sidebar-ring);
}
